func TestListHistory_HappyPath(t *testing.T) {
	var observedQuery string
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		observedQuery = r.URL.RawQuery
		_, _ = w.Write([]byte(`{
			"history": [
				{"id":"102","messagesAdded":[{"message":{"id":"m1","threadId":"t1","labelIds":["INBOX"],"historyId":"102"}}]},
				{"id":"103","labelsAdded":[{"message":{"id":"m2","threadId":"t2"},"labelIds":["STARRED"]}]}
			],
			"historyId": "104",
			"nextPageToken": "next-1",
			"resultSizeEstimate": 2
		}`))
	}))
	defer srv.Close()
	withBaseURL(t, srv.URL)

	c := nonRefreshingClient(t)
	res, err := c.ListHistory(context.Background(), "101", "page-1")
	if err != nil {
		t.Fatalf("ListHistory: %v", err)
	}
	for _, want := range []string{"startHistoryId=101", "pageToken=page-1"} {
		if !strings.Contains(observedQuery, want) {
			t.Fatalf("query %q missing %q", observedQuery, want)
		}
	}
	if res.AccountEmail != "user@example.com" {
		t.Fatalf("AccountEmail = %q want user@example.com", res.AccountEmail)
	}
	if res.HistoryID != "104" || res.NextPageToken != "next-1" || len(res.History) != 2 {
		t.Fatalf("history response wrong: %+v", res)
	}
	if got := res.History[0].MessagesAdded[0].Message.LabelIDs[0]; got != "INBOX" {
		t.Fatalf("first added label = %q want INBOX", got)
	}
}

